impl From<FloatingRateIndex>   for IndexBaseOrSubtype { fn from(x: FloatingRateIndex)   -> Self { Self::FloatingRateIndex(x) } }
impl From<ForeignExchangeRateIndex>   for IndexBaseOrSubtype { fn from(x: ForeignExchangeRateIndex)   -> Self { Self::ForeignExchangeRateIndex(x) } }
impl From<InflationIndex>   for IndexBaseOrSubtype { fn from(x: InflationIndex)   -> Self { Self::InflationIndex(x) } }
impl From<CreditIndex>   for IndexBaseOrSubtype { fn from(x: CreditIndex)   -> Self { Self::CreditIndex(x) } }
impl From<EquityIndex>   for IndexBaseOrSubtype { fn from(x: EquityIndex)   -> Self { Self::EquityIndex(x) } }
